#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return x[0] - y[0];
}
int main() {
    int N;
    scanf("%d", &N);
    int *A = (int *)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    int *points = (int *)malloc(2 * N * sizeof(int));
    for (int i = 0; i < N; i++) {
        points[2 * i] = i;
        points[2 * i + 1] = A[i];
    }
    qsort(points, N, 2 * sizeof(int), compare);
    long long ans = 0;
    for (int i = 0; i < N; i++) {
        for (int j = i + 1; j < N; j++) {
            if (points[2 * i + 1] == points[2 * j + 1] && points[2 * i] < points[2 * j]) {
                ans += (j - i - 1);
            }
        }
    }
    printf("%lld\n", ans % MOD);
    return 0;
}

code.C++:
#include <iostream>
#include <algorithm>
using namespace std;
#define MOD 1000000007
struct Point {
    int x, y;
};
bool compare(const Point &a, const Point &b) {
    return a.x < b.x;
}
int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int N;
    cin >> N;
    Point *points = new Point[N];
    for (int i = 0; i < N; i++) {
        cin >> points[i].y;
        points[i].x = i;
    }
    sort(points, points + N, compare);
    long long ans = 0;
    for (int i = 0; i < N; i++) {
        for (int j = i + 1; j < N; j++) {
            if (points[i].y == points[j].y && points[i].x < points[j].x) {
                ans += (j - i - 1);
            }
        }
    }
    cout << ans % MOD << endl;
    return 0;
}

code.Java:
import java.util.Arrays;
import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[] A = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = sc.nextInt();
        }
        int[][] points = new int[N][2];
        for (int i = 0; i < N; i++) {
            points[i][0] = i;
            points[i][1] = A[i];
        }
        Arrays.sort(points, (a, b) -> a[0] - b[0]);
        long ans = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (points[i][1] == points[j][1] && points[i][0] < points[j][0]) {
                    ans += (j - i - 1);
                }
            }
        }
        System.out.println(ans % MOD);
    }
}

